'use client'
import { useState, useEffect } from 'react'

export default function Nav() {
  const [scrolled, setScrolled] = useState(false)

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20)
    window.addEventListener('scroll', onScroll)
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  return (
    <nav
      className="fixed top-0 left-0 right-0 z-50 transition-all duration-300"
      style={{
        background: scrolled ? 'rgba(255,255,255,0.95)' : 'transparent',
        backdropFilter: scrolled ? 'blur(12px)' : 'none',
        borderBottom: scrolled ? '1px solid #e5e5e5' : '1px solid transparent',
      }}
    >
      <div className="max-w-6xl mx-auto px-5 py-4 flex items-center justify-between">
        <div
          className="font-display text-lg tracking-wide"
          style={{ fontFamily: "'rb-freigeist-neue', 'Arial Black', ui-sans-serif", fontWeight: 700 }}
        >
          FIX SAC<span style={{ color: '#ea2804' }}>TRANSIT</span>
        </div>

        <div className="flex items-center gap-3">
          <div className="flex items-center gap-2">
            <div
              className="pulse-dot rounded-full"
              style={{ width: 6, height: 6, background: '#2b9a66' }}
            />
            <span style={{ fontSize: 11, letterSpacing: '0.15em', color: '#646464', textTransform: 'uppercase' }}>
              Live
            </span>
          </div>

          <a
            href="#trip-planner"
            style={{
              background: '#202020',
              color: '#fcfcfc',
              padding: '8px 20px',
              borderRadius: 9999,
              fontSize: 13,
              fontWeight: 600,
              textDecoration: 'none',
              letterSpacing: '0.05em',
            }}
          >
            Calculate Yours
          </a>
        </div>
      </div>
    </nav>
  )
}
