'use client'
import { useState } from 'react'
import { CityScore, fmtMin } from '../lib/api'

interface TripPlannerProps {
  sac: CityScore | null
}

const STEP_ICONS: Record<string, string> = {
  walk: '🚶',
  bus: '🚍',
  rail: '🚊',
  wait: '⏸',
  transfer: '🔄',
}

const DEFAULT_STEPS = [
  { type: 'walk', label: 'Walk to 35th Ave & 4th stop', detail: '0.2 mi', dur: 4 },
  { type: 'wait', label: 'Wait for Bus 51', detail: 'Next departure: ~28 min', dur: 28 },
  { type: 'bus',  label: 'Bus 51 → Downtown Transfer', detail: '14 stops', dur: 32 },
  { type: 'walk', label: 'Walk to destination', detail: '0.3 mi', dur: 5 },
]

export default function TripPlanner({ sac }: TripPlannerProps) {
  const [origin, setOrigin] = useState('Oak Park, Sacramento')
  const [dest, setDest] = useState('Downtown Sacramento')
  const [loading, setLoading] = useState(false)
  const [result, setResult] = useState<{
    pain: number; transit: number; drive: number; waitPct: number; waitMin: number
  } | null>(null)
  const [error, setError] = useState('')
  const [calculated, setCalculated] = useState(false)

  function swap() {
    setOrigin(dest)
    setDest(origin)
  }

  async function calculate() {
    if (!origin.trim() || !dest.trim()) {
      setError('Enter both an origin and destination.')
      return
    }
    setError('')
    setLoading(true)

    // Stage 2 will have real routing. For now use live Sacramento system data.
    await new Promise(r => setTimeout(r, 900))

    setResult({
      pain: sac?.pain_factor ?? 6.6,
      transit: sac?.transit_minutes ?? 100,
      drive: sac?.drive_minutes ?? 15,
      waitPct: sac?.wait_pct ?? 41,
      waitMin: sac?.wait_minutes ?? 41,
    })
    setCalculated(true)
    setLoading(false)
  }

  function shareOnX() {
    const pain = result?.pain ?? 6.6
    const transit = fmtMin(result?.transit ?? 100)
    const drive = fmtMin(result?.drive ?? 15)
    const text = `My Sacramento commute:\n\n🚍 ${transit} by transit\n🚗 ${drive} by car\n\n${pain}× slower — and we're the state capital.\n\nfixsactransit.org`
    window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent(text)}`, '_blank', 'width=600,height=400')
  }

  return (
    <section id="trip-planner" style={{ background: '#202020', padding: '96px 20px' }}>
      <div className="max-w-6xl mx-auto">
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: 48, alignItems: 'start' }}>

          {/* Left: form */}
          <div>
            <div style={{ fontSize: 11, letterSpacing: '0.22em', color: '#646464', textTransform: 'uppercase', marginBottom: 12, fontFamily: 'JetBrains Mono, monospace' }}>
              Calculate your pain ratio
            </div>
            <h2
              style={{
                fontFamily: "'rb-freigeist-neue', 'Arial Black', ui-sans-serif",
                fontWeight: 700,
                fontSize: 'clamp(40px, 6vw, 72px)',
                lineHeight: 0.9,
                letterSpacing: '-0.02em',
                color: '#ffffff',
                marginBottom: 40,
              }}
            >
              YOUR<br />
              <span style={{ color: '#ea2804' }}>COMMUTE</span>
            </h2>

            {/* Origin */}
            <div style={{ marginBottom: 8 }}>
              <label style={{ fontSize: 9, letterSpacing: '0.2em', color: '#646464', textTransform: 'uppercase', display: 'block', marginBottom: 6, fontFamily: 'JetBrains Mono, monospace' }}>
                From
              </label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: 16, top: '50%', transform: 'translateY(-50%)', fontSize: 14, pointerEvents: 'none' }}>📍</span>
                <input
                  type="text"
                  value={origin}
                  onChange={e => setOrigin(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && calculate()}
                  placeholder="Oak Park, Sacramento"
                  style={{
                    width: '100%',
                    background: 'rgba(255,255,255,0.06)',
                    border: '1px solid rgba(255,255,255,0.12)',
                    borderRadius: 9999,
                    color: '#ffffff',
                    fontFamily: 'JetBrains Mono, monospace',
                    fontSize: 13,
                    padding: '13px 20px 13px 44px',
                    outline: 'none',
                  }}
                />
              </div>
            </div>

            {/* Swap */}
            <div style={{ display: 'flex', justifyContent: 'center', margin: '4px 0', position: 'relative', zIndex: 2 }}>
              <button
                onClick={swap}
                style={{
                  background: 'rgba(255,255,255,0.08)',
                  border: '1px solid rgba(255,255,255,0.15)',
                  borderRadius: 9999,
                  width: 32, height: 32,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  cursor: 'pointer',
                  color: '#ffffff',
                  fontSize: 14,
                  transition: 'background 0.15s',
                }}
              >
                ⇅
              </button>
            </div>

            {/* Dest */}
            <div style={{ marginBottom: 20 }}>
              <label style={{ fontSize: 9, letterSpacing: '0.2em', color: '#646464', textTransform: 'uppercase', display: 'block', marginBottom: 6, fontFamily: 'JetBrains Mono, monospace' }}>
                To
              </label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: 16, top: '50%', transform: 'translateY(-50%)', fontSize: 14, pointerEvents: 'none' }}>🏁</span>
                <input
                  type="text"
                  value={dest}
                  onChange={e => setDest(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && calculate()}
                  placeholder="Downtown Sacramento"
                  style={{
                    width: '100%',
                    background: 'rgba(255,255,255,0.06)',
                    border: '1px solid rgba(255,255,255,0.12)',
                    borderRadius: 9999,
                    color: '#ffffff',
                    fontFamily: 'JetBrains Mono, monospace',
                    fontSize: 13,
                    padding: '13px 20px 13px 44px',
                    outline: 'none',
                  }}
                />
              </div>
            </div>

            {error && (
              <div style={{ fontSize: 12, color: '#ea2804', marginBottom: 12, fontFamily: 'JetBrains Mono, monospace' }}>
                {error}
              </div>
            )}

            <button
              onClick={calculate}
              disabled={loading}
              style={{
                width: '100%',
                background: loading ? 'rgba(234,40,4,0.5)' : '#ea2804',
                color: '#ffffff',
                border: 'none',
                borderRadius: 9999,
                fontFamily: 'JetBrains Mono, monospace',
                fontSize: 13,
                fontWeight: 600,
                letterSpacing: '0.15em',
                textTransform: 'uppercase',
                padding: '15px 24px',
                cursor: loading ? 'not-allowed' : 'pointer',
                transition: 'opacity 0.15s',
                outline: '3px solid rgba(234,40,4,0.3)',
                outlineOffset: 2,
              }}
            >
              {loading ? 'Routing...' : 'Calculate Pain Ratio'}
            </button>

            {!calculated && (
              <div style={{
                marginTop: 20,
                padding: '16px 20px',
                border: '1px dashed rgba(255,255,255,0.12)',
                borderRadius: 16,
                fontSize: 11,
                color: '#646464',
                fontFamily: 'JetBrains Mono, monospace',
                letterSpacing: '0.06em',
                lineHeight: 1.7,
              }}>
                Live address-level routing coming in Stage 2.<br />
                Currently uses Sacramento system data.
              </div>
            )}
          </div>

          {/* Right: result */}
          <div style={{ opacity: calculated ? 1 : 0.3, transition: 'opacity 0.4s' }}>
            {/* Pain card */}
            <div style={{
              border: '1px solid rgba(255,255,255,0.1)',
              borderRadius: 24,
              overflow: 'hidden',
            }}>
              {/* Head */}
              <div style={{
                background: 'rgba(255,255,255,0.05)',
                padding: '14px 20px',
                borderBottom: '1px solid rgba(255,255,255,0.08)',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
              }}>
                <span style={{ fontSize: 11, color: '#646464', letterSpacing: '0.15em', textTransform: 'uppercase', fontFamily: 'JetBrains Mono, monospace' }}>
                  {origin.split(',')[0]} → {dest.split(',')[0]}
                </span>
                <span style={{
                  background: '#ea2804',
                  color: 'white',
                  fontSize: 9,
                  fontWeight: 600,
                  letterSpacing: '0.1em',
                  textTransform: 'uppercase',
                  padding: '3px 10px',
                  borderRadius: 9999,
                }}>
                  Live
                </span>
              </div>

              {/* Pain number */}
              <div style={{ padding: '24px 24px 8px' }}>
                <div style={{
                  fontFamily: "'rb-freigeist-neue', 'Arial Black', ui-sans-serif",
                  fontWeight: 700,
                  fontSize: 96,
                  lineHeight: 0.85,
                  color: '#ea2804',
                }}>
                  {result?.pain ?? '—'}×
                </div>
                <div style={{ fontSize: 10, letterSpacing: '0.2em', color: '#646464', textTransform: 'uppercase', marginTop: 10, fontFamily: 'JetBrains Mono, monospace' }}>
                  Times slower than driving
                </div>
              </div>

              {/* Times */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', borderTop: '1px solid rgba(255,255,255,0.08)' }}>
                <div style={{ padding: '16px 24px', borderRight: '1px solid rgba(255,255,255,0.08)' }}>
                  <div style={{ fontSize: 9, letterSpacing: '0.18em', color: '#646464', textTransform: 'uppercase', marginBottom: 4, fontFamily: 'JetBrains Mono, monospace' }}>By Transit</div>
                  <div style={{ fontFamily: "'rb-freigeist-neue', 'Arial Black', ui-sans-serif", fontWeight: 700, fontSize: 32, color: '#ea2804' }}>
                    {fmtMin(result?.transit ?? null)}
                  </div>
                </div>
                <div style={{ padding: '16px 24px' }}>
                  <div style={{ fontSize: 9, letterSpacing: '0.18em', color: '#646464', textTransform: 'uppercase', marginBottom: 4, fontFamily: 'JetBrains Mono, monospace' }}>By Car</div>
                  <div style={{ fontFamily: "'rb-freigeist-neue', 'Arial Black', ui-sans-serif", fontWeight: 700, fontSize: 32, color: '#ffffff' }}>
                    {fmtMin(result?.drive ?? null)}
                  </div>
                </div>
              </div>

              {/* Wait stat */}
              {result && (
                <div style={{ padding: '14px 24px', borderTop: '1px solid rgba(255,255,255,0.08)' }}>
                  <div style={{ height: 2, background: 'rgba(255,255,255,0.08)', borderRadius: 9999, position: 'relative', marginBottom: 8 }}>
                    <div style={{
                      position: 'absolute', left: 0, top: 0, height: '100%',
                      width: `${result.waitPct}%`,
                      background: '#ea2804',
                      borderRadius: 9999,
                      transition: 'width 1.5s cubic-bezier(0.16,1,0.3,1)',
                    }} />
                  </div>
                  <div style={{ fontSize: 11, color: '#646464', fontFamily: 'JetBrains Mono, monospace', letterSpacing: '0.04em' }}>
                    <span style={{ color: '#ea2804', fontWeight: 600 }}>{result.waitPct}%</span> of this trip is waiting at stops — {result.waitMin} min standing still.
                  </div>
                </div>
              )}

              {/* Steps */}
              <div style={{ borderTop: '1px solid rgba(255,255,255,0.08)', padding: '14px 24px' }}>
                {DEFAULT_STEPS.map((step, i) => (
                  <div
                    key={i}
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: 12,
                      padding: '7px 0',
                      borderBottom: i < DEFAULT_STEPS.length - 1 ? '1px solid rgba(255,255,255,0.05)' : 'none',
                      fontSize: 11,
                      color: step.type === 'wait' ? '#ea2804' : '#8d8d8d',
                      fontFamily: 'JetBrains Mono, monospace',
                      letterSpacing: '0.04em',
                    }}
                  >
                    <span style={{ width: 20, textAlign: 'center' }}>{STEP_ICONS[step.type]}</span>
                    <span style={{ flex: 1 }}>
                      {step.label}
                      <span style={{ display: 'block', fontSize: 9, color: '#4e4e4e', marginTop: 1 }}>{step.detail}</span>
                    </span>
                    <span style={{ fontSize: 10, color: '#4e4e4e' }}>{step.dur}m</span>
                  </div>
                ))}
              </div>

              {/* Share */}
              {calculated && (
                <div style={{ padding: '14px 24px', borderTop: '1px solid rgba(255,255,255,0.08)', display: 'flex', gap: 10 }}>
                  <button
                    onClick={shareOnX}
                    style={{
                      flex: 1,
                      background: '#ea2804',
                      color: 'white',
                      border: 'none',
                      borderRadius: 9999,
                      padding: '11px 16px',
                      fontSize: 11,
                      fontWeight: 600,
                      letterSpacing: '0.12em',
                      textTransform: 'uppercase',
                      cursor: 'pointer',
                      fontFamily: 'JetBrains Mono, monospace',
                    }}
                  >
                    Share on X
                  </button>
                  <button
                    onClick={() => navigator.clipboard.writeText('https://fixsactransit.org')}
                    style={{
                      flex: 1,
                      background: 'transparent',
                      color: '#8d8d8d',
                      border: '1px solid rgba(255,255,255,0.12)',
                      borderRadius: 9999,
                      padding: '11px 16px',
                      fontSize: 11,
                      fontWeight: 600,
                      letterSpacing: '0.12em',
                      textTransform: 'uppercase',
                      cursor: 'pointer',
                      fontFamily: 'JetBrains Mono, monospace',
                    }}
                  >
                    Copy Link
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </section>
  )
}
